#include <iostream>
#include <string>

class Str {
private:
    char* data_; // Assuming this is your internal representation
public:
    // Constructors, destructor, etc. not shown for brevity

    // Conversion function to std::string for easy output
    std::string toString() const {
        return std::string(data_);
    }

    // Friend declaration for operator<< and operator>>
    friend std::istream& operator>>(std::istream& istr, Str& s);
    friend std::ostream& operator<<(std::ostream& ostr, const Str& s);
